import{_ as a,o as d,c as e,a2 as i}from"./chunks/framework.ZhLefgN8.js";const _=JSON.parse('{"title":"账户切换","description":"","frontmatter":{"layout":"doc","sidebar":true},"headers":[],"relativePath":"account/account-switching.md","filePath":"zh-CN/account/account-switching.md"}'),l={name:"account/account-switching.md"};function r(o,t,n,c,h,s){return d(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="账户切换" tabindex="-1">账户切换 <a class="header-anchor" href="#账户切换" aria-label="Permalink to &quot;账户切换&quot;">​</a></h1><p>长桥支持同一登录账号下持有多个证券账户，账户切换功能允许用户在不同账户之间快速切换，独立查看各账户的资产和交易情况。</p><h2 id="页面入口" tabindex="-1">页面入口 <a class="header-anchor" href="#页面入口" aria-label="Permalink to &quot;页面入口&quot;">​</a></h2><p>资产页顶部账户名称区域 → 点击账户名称，底部弹出「选择账户」面板。</p><h2 id="支持的账户类型" tabindex="-1">支持的账户类型 <a class="header-anchor" href="#支持的账户类型" aria-label="Permalink to &quot;支持的账户类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>账户名称</th><th>账户类型</th><th>账号格式</th><th>说明</th></tr></thead><tbody><tr><td>长桥综合账户</td><td>融资账户（主账户）</td><td>H10***539</td><td>香港主账户，支持港股、美股等多市场交易</td></tr><tr><td>长桥综合账户（日内融）</td><td>Intraday Financing</td><td>H10***721</td><td>支持日内融资交易的账户</td></tr><tr><td>长桥 SG 综合账户</td><td>融资账户</td><td>SG1***100</td><td>新加坡综合账户</td></tr><tr><td>长桥标准账户</td><td>融资账户</td><td>113***982</td><td>长桥标准版账户</td></tr><tr><td>模拟炒股</td><td>融资账户</td><td>LBP***243</td><td>虚拟资金模拟交易账户，不涉及真实资金</td></tr></tbody></table><blockquote><p>实际账户类型以用户开户情况为准，不同用户持有的账户组合可能不同。</p></blockquote><h2 id="账户面板信息" tabindex="-1">账户面板信息 <a class="header-anchor" href="#账户面板信息" aria-label="Permalink to &quot;账户面板信息&quot;">​</a></h2><p>切换面板中每个账户条目显示：</p><ul><li>账户名称</li><li>账户类型标签（如「主账户」「日内融」）</li><li>账号（点击可复制）</li></ul><h2 id="操作方式" tabindex="-1">操作方式 <a class="header-anchor" href="#操作方式" aria-label="Permalink to &quot;操作方式&quot;">​</a></h2><ol><li>点击资产页顶部的当前账户名称</li><li>底部弹出账户列表，展示所有可用账户</li><li>点击目标账户即可切换，页面刷新显示该账户的资产数据</li></ol><h2 id="账户数据独立性与操作提示" tabindex="-1">账户数据独立性与操作提示 <a class="header-anchor" href="#账户数据独立性与操作提示" aria-label="Permalink to &quot;账户数据独立性与操作提示&quot;">​</a></h2><ul><li>不同账户的资产、持仓、订单记录相互独立</li><li>切换账户不影响登录状态</li><li>模拟炒股账户使用虚拟资金，操作不影响真实账户</li><li>出金、股票转仓等操作请确认当前所在账户</li></ul>',14)])])}const b=a(l,[["render",r]]);export{_ as __pageData,b as default};
